1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a cell alive that has exactly 2 live neighbors (survival)", () => {
15	    const liveCells: [number, number][] = [[0, 0], [1, 0], [0, 1]];
16	    const result = nextGeneration(liveCells);
17	    expect(result).toContainEqual([0, 0]);
18	  });
19	  it("should keep a cell alive that has exactly 3 live neighbors (survival)", () => {
20	    const liveCells: [number, number][] = [[0, 0], [1, 0], [2, 0], [1, 1]];
21	    const result = nextGeneration(liveCells);
22	    expect(result).toContainEqual([1, 0]);
23	  });
24	  it("should kill a cell that has 4 live neighbors (overpopulation)", () => {
25	    const liveCells: [number, number][] = [[0, 1], [1, 0], [1, 1], [1, 2], [2, 1]];
26	    const result = nextGeneration(liveCells);
27	    expect(result).not.toContainEqual([1, 1]);
28	  });
29	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
30	    const liveCells: [number, number][] = [[0, 1], [1, 1], [0, 0]];
31	    const result = nextGeneration(liveCells);
32	    expect(result).toContainEqual([1, 0]);
33	  });
34	  it.todo("should keep a block pattern unchanged (still life)");
35	  it.todo("should oscillate a blinker pattern to its alternate form");
36	});
