1	function cellKey(x: number, y: number): string {
2	  return `${x},${y}`;
3	}
4	
5	function parseKey(key: string): [number, number] {
6	  const [x, y] = key.split(",").map(Number);
7	  return [x, y];
8	}
9	
10	export function nextGeneration(
11	  livingCells: [number, number][]
12	): [number, number][] {
13	  const alive = new Set(livingCells.map(([x, y]) => cellKey(x, y)));
14	
15	  const neighborOffsets: [number, number][] = [
16	    [-1, -1], [-1, 0], [-1, 1],
17	    [0, -1],           [0, 1],
18	    [1, -1],  [1, 0],  [1, 1],
19	  ];
20	
21	  function countLiveNeighbors(x: number, y: number): number {
22	    let count = 0;
23	    for (const [dx, dy] of neighborOffsets) {
24	      if (alive.has(cellKey(x + dx, y + dy))) {
25	        count++;
26	      }
27	    }
28	    return count;
29	  }
30	
31	  const result: [number, number][] = [];
32	
33	  // Survival: live cells with 2 or 3 neighbors survive
34	  for (const [x, y] of livingCells) {
35	    const neighbors = countLiveNeighbors(x, y);
36	    if (neighbors === 2 || neighbors === 3) {
37	      result.push([x, y]);
38	    }
39	  }
40	
41	  // Birth: dead cells adjacent to live cells with exactly 3 neighbors come alive
42	  const deadCandidates = new Set<string>();
43	  for (const [x, y] of livingCells) {
44	    for (const [dx, dy] of neighborOffsets) {
45	      const key = cellKey(x + dx, y + dy);
46	      if (!alive.has(key)) {
47	        deadCandidates.add(key);
48	      }
49	    }
50	  }
51	  for (const key of deadCandidates) {
52	    const cell = parseKey(key);
53	    if (countLiveNeighbors(...cell) === 3) {
54	      result.push(cell);
55	    }
56	  }
57	
58	  return result;
59	}
